<?php require_once __DIR__.'/config/auth.php'; require_once __DIR__.'/components.php';$id=(int)($_GET['id']??0);$stmt=db()->prepare('SELECT cards.*,users.username FROM cards JOIN users ON users.id=cards.user_id WHERE cards.id=? AND cards.visibility="Public" LIMIT 1');$stmt->bind_param('i',$id);$stmt->execute();$card=$stmt->get_result()->fetch_assoc();require_once __DIR__.'/header.php';if(!$card)echo '<div class="panel empty"><h3>Item not found</h3><p class="muted">This item is private or does not exist.</p></div>';else{echo '<div class="actions" style="margin-bottom:14px"><span class="chip">Shared from Link-Locker by @'.e($card['username']).'</span></div><div class="grid">';render_card($card,false);echo '</div>';}require_once __DIR__.'/footer.php'; ?>